import './index.css';

import {
  Link
} from 'react-router-dom';

function TeacherDashboard() {

  const user =
    JSON.parse(
      localStorage.getItem('user')
    );

  return (

    <div className="dashboard">

      <h1>
        Teacher Dashboard
      </h1>

      <div className="card">

        <h2>
          Welcome
          {' '}
          {user?.name}
        </h2>

      </div>

      <div className="links">

        <Link to="/subjects">

          Manage Subjects

        </Link>

        <Link to="/add-student">

          Add Student

        </Link>

        <Link to="/add-marks">

          Add Marks

        </Link>

      </div>

    </div>

  );

}

export default TeacherDashboard;
